<PageTitle>Job Application</PageTitle>

<h1>Job Application</h1>

@* Step Indicator Bar *@
<div class="step-indicator">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var stepClass = GetStepClass(stepIndex);
        <div class="step @stepClass" @onclick="() => GoToStep(stepIndex)">
            <div class="step-circle">
                @if (stepIndex < CurrentStep)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <div class="step-label">@StepNames[stepIndex]</div>
        </div>
        @if (i < StepNames.Length - 1)
        {
            <div class="step-connector @(stepIndex < CurrentStep ? "completed" : "")"></div>
        }
    }
</div>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger mt-3">@ErrorMessage</div>
}

@* Step Content *@
<div class="step-content mt-4">
    @switch (CurrentStep)
    {
        case 0:
            <StepPersonalInfo />
            break;
        case 1:
            <StepWorkHistory />
            break;
        case 2:
            <StepReferences />
            break;
        case 3:
            <StepCoverLetter />
            break;
        case 4:
            <StepReview />
            break;
    }
</div>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int CurrentStep { get; set; } = 0;
    private string? ErrorMessage { get; set; }
    private bool IsSubmitting { get; set; }
    private int? SubmittedApplicationId { get; set; }

    // Form state
    private string FullName { get; set; } = "";
    private string Email { get; set; } = "";
    private string Phone { get; set; } = "";
    private string Address { get; set; } = "";

    private List<WorkEntryModel> WorkEntries { get; set; } = new() { new WorkEntryModel() };

    private List<ReferenceModel> References { get; set; } = new() { new ReferenceModel(), new ReferenceModel() };

    private string CoverLetter { get; set; } = "";
    private const int CoverLetterMaxLength = 2000;

    private string GetStepClass(int step)
    {
        if (step == CurrentStep) return "active";
        if (step < CurrentStep) return "completed";
        return "future";
    }

    private void GoToStep(int step)
    {
        if (step < CurrentStep)
        {
            CurrentStep = step;
            ErrorMessage = null;
        }
    }

    private async Task NextStep()
    {
        ErrorMessage = null;

        if (!ValidateCurrentStep())
            return;

        if (CurrentStep == 0)
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Email);
            if (!emailValid)
            {
                ErrorMessage = "Please enter a valid email address.";
                return;
            }
        }

        if (CurrentStep < StepNames.Length - 1)
            CurrentStep++;
    }

    private void PreviousStep()
    {
        ErrorMessage = null;
        if (CurrentStep > 0)
            CurrentStep--;
    }

    private bool ValidateCurrentStep()
    {
        switch (CurrentStep)
        {
            case 0:
                if (string.IsNullOrWhiteSpace(FullName))
                { ErrorMessage = "Full name is required."; return false; }
                if (string.IsNullOrWhiteSpace(Email))
                { ErrorMessage = "Email is required."; return false; }
                if (string.IsNullOrWhiteSpace(Phone))
                { ErrorMessage = "Phone is required."; return false; }
                if (string.IsNullOrWhiteSpace(Address))
                { ErrorMessage = "Address is required."; return false; }
                return true;
            case 1:
                foreach (var entry in WorkEntries)
                {
                    if (string.IsNullOrWhiteSpace(entry.Company))
                    { ErrorMessage = "Company name is required for all entries."; return false; }
                    if (string.IsNullOrWhiteSpace(entry.Title))
                    { ErrorMessage = "Job title is required for all entries."; return false; }
                    if (entry.StartDate == default)
                    { ErrorMessage = "Start date is required for all entries."; return false; }
                }
                return true;
            case 2:
                foreach (var reference in References)
                {
                    if (string.IsNullOrWhiteSpace(reference.Name))
                    { ErrorMessage = "Name is required for all references."; return false; }
                    if (string.IsNullOrWhiteSpace(reference.Relationship))
                    { ErrorMessage = "Relationship is required for all references."; return false; }
                    if (string.IsNullOrWhiteSpace(reference.Email))
                    { ErrorMessage = "Email is required for all references."; return false; }
                    if (string.IsNullOrWhiteSpace(reference.Phone))
                    { ErrorMessage = "Phone is required for all references."; return false; }
                }
                return true;
            case 3:
                if (string.IsNullOrWhiteSpace(CoverLetter))
                { ErrorMessage = "Cover letter is required."; return false; }
                if (CoverLetter.Length > CoverLetterMaxLength)
                { ErrorMessage = $"Cover letter must be {CoverLetterMaxLength} characters or fewer."; return false; }
                return true;
            default:
                return true;
        }
    }

    private async Task SubmitApplication()
    {
        ErrorMessage = null;
        IsSubmitting = true;

        try
        {
            var personal = new PersonalInfo(FullName, Email, Phone, Address);
            var workEntries = WorkEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList();
            var work = new WorkHistory(workEntries);
            var refs = References.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();

            var application = new JobApplication(personal, work, refs, CoverLetter);
            SubmittedApplicationId = await ApplicationService.SubmitApplicationAsync(application);
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }

    private void AddWorkEntry()
    {
        WorkEntries.Add(new WorkEntryModel());
    }

    private void RemoveWorkEntry(WorkEntryModel entry)
    {
        if (WorkEntries.Count > 1)
            WorkEntries.Remove(entry);
    }

    private void AddReference()
    {
        if (References.Count < 3)
