+                    <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Phone</dd>
+                    <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Address</dd>
+                </dl>
+            </div>
+
+            <div class="card mb-3 p-3">
+                <div class="d-flex justify-content-between align-items-center">
+                    <h5>Work History</h5>
+                    <a href="javascript:void(0)" @onclick='() => GoToStep(1)'>Edit</a>
+                </div>
+                @foreach (var entry in WorkEntries)
+                {
+                    <div class="mb-2 border-bottom pb-2">
+                        <strong>@entry.Title</strong> at @entry.Company<br />
+                        <small>@entry.StartDate.ToString("MMM yyyy") — @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")</small>
+                        @if (!string.IsNullOrWhiteSpace(entry.Description))
+                        {
+                            <p class="mb-0 mt-1">@entry.Description</p>
+                        }
+                    </div>
+                }
+            </div>
+
+            <div class="card mb-3 p-3">
+                <div class="d-flex justify-content-between align-items-center">
+                    <h5>References</h5>
+                    <a href="javascript:void(0)" @onclick='() => GoToStep(2)'>Edit</a>
+                </div>
+                @foreach (var reference in References)
+                {
+                    <div class="mb-2">
+                        <strong>@reference.Name</strong> (@reference.Relationship)<br />
+                        <small>@reference.Email | @reference.Phone</small>
+                    </div>
+                }
+            </div>
+
+            <div class="card mb-3 p-3">
+                <div class="d-flex justify-content-between align-items-center">
+                    <h5>Cover Letter</h5>
+                    <a href="javascript:void(0)" @onclick='() => GoToStep(3)'>Edit</a>
+                </div>
+                <p style="white-space: pre-wrap;">@CoverLetter</p>
+            </div>
+
+            <div class="d-flex justify-content-between">
+                <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
+                <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@IsSubmitting">
+                    @if (IsSubmitting)
+                    {
+                        <span class="spinner-border spinner-border-sm me-2"></span>
+                    }
+                    Submit Application
+                </button>
+            </div>
+        }
+    };
+}
